func:
// Filtrace bazénu v5 — §10 (přepracováno 25.6.2026)
// Doba D = filtrace_doba_min (dashboard slider). Min SOUVISLÝ BLOK = D/2 (bez ohledu na FVE).
// STUDENÁ voda (< threshold): časově — jede D, žádná chlorace.
// TEPLÁ voda (>= threshold): povinný blok D/2 + dohánění ORP (min 680 / ideál 720).
// ORP (sensor.exo_pool_orp) je platná JEN za běhu filtrace → ukládá se poslední platná.
// Hard cut-off: poolT <= filtrace_pool_temp_min (5 °C) → NEBĚŽÍ.

// === Konfigurace ===
var cfg = global.get("fve_config") || {};
var S_ON      = cfg.filtrace_surplus_on_w        || 2500;
var S_OFF     = cfg.filtrace_surplus_off_w       || 1500;
var T_MIN     = cfg.filtrace_pool_temp_min       || 5;
var T_THRESH  = cfg.filtrace_pool_temp_threshold_c || 10;
var T_HYST    = cfg.filtrace_pool_temp_hysterese_c || 1;
var D         = cfg.filtrace_doba_min            || 120;
var HALF      = Math.max(2, Math.round(D / 2));
var ORP_MIN   = cfg.filtrace_min_chlorace        || 680;
var ORP_IDEAL = cfg.filtrace_ideal_chlorace      || 720;
var ORP_STAB  = cfg.filtrace_orp_stabilizace_min || 5;
var DEAD      = cfg.filtrace_deadline_h          || 23;
var ANTI      = (cfg.filtrace_anti_cycle_min     || 10) * 60 * 1000;
var SOC_LOW   = cfg.filtrace_soc_low             || 40;
var SOLAR_OK  = cfg.filtrace_solar_ok_kwh        || 10;
var TICK = 2;

// === Vstupní data ===
var fOn = msg.filtraceState === "on";
var autoOn = (msg.automatizovatFiltrace === "on");
if (msg.automatizovatFiltrace === undefined || msg.automatizovatFiltrace === null || msg.automatizovatFiltrace === "") {
    var _autoE = global.get("homeassistant.homeAssistant.states['input_boolean.automatizovat_filtraci_v_bazenu']") || {};
    autoOn = _autoE.state === "on";
}
var surplus = parseFloat(msg.solarSurplus) || 0;
var soc = parseFloat(msg.batterySoc) || 0;

var nibeCompE = global.get("homeassistant.homeAssistant.states['binary_sensor.nibe_kompresory_aktivni_binarni']") || {};
var nibeComp = nibeCompE.state === "on";

var isZapNak = (global.get("fve_current_mode") || "") === "zaporna_nakupni_cena";
var gridE = global.get("homeassistant.homeAssistant.states['sensor.spotreba_ze_site']") || {};
var gridDraw = parseFloat(gridE.state) || 0;
var maxGrid = cfg.max_spotreba_sit_w || 22000;
var FILT_W = 2500;
var hasHeadroom = (maxGrid - gridDraw) >= FILT_W;

var tE = global.get("homeassistant.homeAssistant.states['sensor.hp2551ae_pro_v2_1_0_temperature_1']") || {};
var poolT = parseFloat(tE.state);
if (isNaN(poolT)) poolT = 0;

// === Pásmo teploty s hysterezí (§10.3) ===
var band = flow.get("filt_temp_band") || "";
if (poolT >= T_THRESH) { band = "tepla"; }
else if (poolT < (T_THRESH - T_HYST)) { band = "studena"; }
else if (band === "") { band = (poolT >= T_THRESH) ? "tepla" : "studena"; }
flow.set("filt_temp_band", band);

var coldLock = (poolT < T_MIN && poolT > 0);   // poolT==0 = neznámá → ignoruj cut-off
var warm = (band === "tepla") && !coldLock;

// === FVE plán ===
var planData = global.get("fve_plan") || {};
var plan = planData.plan || [];
var cur = plan.length > 0 ? plan[0] : {};
var mode = cur.mode || "setrit";
var pLvl = cur.priceLevel || 0;
var remE = global.get("homeassistant.homeAssistant.states['sensor.energy_production_today_remaining_3']") || {};
var solRemain = parseFloat(remE.state) || 0;

// === Čas ===
var dnow = new Date();
var tp = dnow.toLocaleTimeString("en-GB", {timeZone: "Europe/Prague", hour12: false}).split(":");
var hr = parseInt(tp[0]), mn = parseInt(tp[1]);
var nowM = hr * 60 + mn;
var now = dnow.getTime();
var today = dnow.toLocaleDateString("en-CA", {timeZone: "Europe/Prague"});

// === Denní tracker (persistence) ===
var sDate = flow.get("filt_date") || "";
var run = flow.get("filt_run") || 0;
var doneToday = flow.get("filt_done") === true;
var newDay = today !== sDate;
var isRestart = sDate === "";
if (isRestart) {
    var _saved = {};
    try { _saved = JSON.parse(fs.readFileSync("/homeassistant/filt_counter.json", "utf8")); } catch(e) { _saved = {}; }
    if (_saved.date === today) { run = _saved.run || 0; doneToday = _saved.done === true; }
    flow.set("filt_date", today); flow.set("filt_run", run); flow.set("filt_done", doneToday);
    try { var _orpS = JSON.parse(fs.readFileSync("/homeassistant/filt_orp.json", "utf8")); if (_orpS && typeof _orpS.v === "number") global.set("filtrace_orp_last_valid", _orpS); } catch(e) {}
} else if (newDay) {
    run = 0; doneToday = false; flow.set("filt_date", today); flow.set("filt_run", 0); flow.set("filt_done", false);
    flow.set("filt_block_done_date", "");
}
if (fOn) { run += TICK; flow.set("filt_run", run); }
try { fs.writeFileSync("/homeassistant/filt_counter.json", JSON.stringify({date: today, run: run, done: doneToday})); } catch(e) {}
global.set("filt_persist", {date: today, run: run, done: doneToday});

// === Souvislý blok ===
var contStart = flow.get("filt_cont_start") || 0;
if (fOn && !(flow.get("filt_was_on"))) { contStart = now; flow.set("filt_cont_start", now); }
flow.set("filt_was_on", fOn);
var contRunMin = fOn ? (now - contStart) / 60000 : 0;
var blockOk = contRunMin >= HALF;                       // aktuální souvislý blok dosáhl D/2
var mandatoryMet = run >= HALF;                         // povinné minimum (½ doby) splněno dnes — z persistovaného čítače (robustní vůči restartu)

// === ORP (chlorace) — platná JEN za běhu, ukládej poslední platnou po ustálení ===
var orpE = global.get("homeassistant.homeAssistant.states['sensor.exo_pool_orp']") || {};
var orpNow = parseFloat(orpE.state);
if (fOn && contRunMin >= ORP_STAB && !isNaN(orpNow) && orpNow > 0) {
    var _orpRec = {v: orpNow, t: now, date: today};
    global.set("filtrace_orp_last_valid", _orpRec);
    try { fs.writeFileSync("/homeassistant/filt_orp.json", JSON.stringify(_orpRec)); } catch(e) {}
}
var orpLV = global.get("filtrace_orp_last_valid") || {};
var orpValid = (typeof orpLV.v === "number");
var orp = orpValid ? orpLV.v : null;
var orpFreshToday = orpValid && orpLV.date === today;
var orpIdealMet = warm && orpValid && orp >= ORP_IDEAL;            // ideál splněn → smí přerušit (§10.5 a)
var orpBelowMin = warm && (!orpValid || orp < ORP_MIN);           // pod minimem (neznámá = ber jako pod min)

// === §11.4 POOL Heating filtrace lock — FORCE ON ===
var poolLockUntil = parseInt(global.get("pool_heating_filtrace_lock_until")) || 0;
// FIX (28.6.2026, §11.4): force-on JEN kdyz pool REALNE topi TED (ventil ON nebo NIBE->bazen ON).
// Doznivajici/zaseknuty lock bez aktivniho topeni NESMI spoustet filtraci (user: zadne spousteni bez duvodu).
var _vSmesE = global.get("homeassistant.homeAssistant.states['switch.bazen_ventil_smesovac']") || {};
var _nbBoostE = global.get("homeassistant.homeAssistant.states['switch.nibe_jednorazove_zvyseni_tuv']") || {};
var poolHeatingActive = (_vSmesE.state === "on") || (_nbBoostE.state === "on");
if (poolLockUntil > now && autoOn && poolHeatingActive) {
    var _lockRemMin = Math.ceil((poolLockUntil - now) / 60000);
    var _outLock = [null, null, null, null];
    if (!fOn) { _outLock[0] = {payload: "on", reason: "POOL lock " + _lockRemMin + "min"}; flow.set("filt_on_ts", now); }
    global.set("filtrace_status", {run: run, target: D, half: HALF, met: run >= D, orp: orp, band: band, lock: true});
    node.status({fill: "blue", shape: "dot", text: "POOL LOCK " + _lockRemMin + "m | " + run + "min"});
    return _outLock;
}

// === Analýza budoucího solaru ===
var futureSolar = 0;
for (var i = 1; i < plan.length; i++) { if (plan[i].isSolarHour) futureSolar++; }
var hasFutureSolar = futureSolar > 0 || solRemain >= SOLAR_OK;

// === Cíle / stavy ===
var target = coldLock ? 0 : D;                     // denní cílová doba (obě pásma míří na D)
var rem = Math.max(0, target - run);
var met = rem <= 0;                                // nastavená doba D splněna
var minToDead = Math.max(0, (DEAD * 60) - nowM);
var urgentMand = !mandatoryMet && target > 0 && minToDead <= (HALF - run + 15);  // povinný blok nestihne → urgent

// Podmínky výhodnosti
var gSurp = surplus >= S_ON;                       // solární přebytek (zdarma)
var oSurp = surplus >= S_OFF;                       // hystereze pro setrvání
var inSetrit = mode === "setrit";
var inNormal = mode === "normal";
var lowSOC = soc < SOC_LOW;
var nightReserveSoc = (planData && planData.sellTargetSoc != null) ? planData.sellTargetSoc : SOC_LOW;
var batLowForNight = soc <= nightReserveSoc;

// "Dobré okno" pro filtraci (preferované podmínky)
var goodWindow = gSurp || (isZapNak && hasHeadroom) || (inSetrit && !hasFutureSolar);
// "Free okno" pro dohánění chlorace nad rámec povinného bloku — jen zdarma, NIKDY z baterie/gridu
var chaseWindow = gSurp || (isZapNak && hasHeadroom);

var lastOn = flow.get("filt_on_ts") || 0;
var lastOff = flow.get("filt_off_ts") || 0;

// === Denní LATCH (§10.5, user 26.6.2026): jakmile dnes splněn ČAS + MIN CHLORACE → filtrace už ten den NEBĚŽÍ ===
// Výjimka: finanční důvod (záporná nákupní cena / omezení výroby = dump load). NIKDY znovu honit ORP po splnění.
var chlorReached = warm ? (orpValid && orp >= ORP_MIN) : true;   // studená voda chloraci neřeší
if (!doneToday && met && chlorReached) { doneToday = true; flow.set("filt_done", true); }
var sellNow = (cur && cur.priceSell != null) ? parseFloat(cur.priceSell) : 1; if (isNaN(sellNow)) sellNow = 1;
var curtail = (mode === "zakaz_pretoku") || (sellNow <= 0);
var financialRun = (isZapNak && hasHeadroom) || (curtail && gSurp && hasHeadroom);
try { fs.writeFileSync("/homeassistant/filt_counter.json", JSON.stringify({date: today, run: run, done: doneToday})); } catch(e) {}

// === ROZHODOVÁNÍ ===
var act = "none", rsn = "";

if (autoOn) {
if (!fOn) {
    // 0a. Hard cut-off
    if (coldLock) {
        global.set("filtrace_status", {run: run, target: target, half: HALF, met: true, orp: orp, band: band, coldLock: true});
        node.status({fill: "blue", shape: "ring", text: "Pool " + poolT + "°C < " + T_MIN + "°C → freeze"});
        return [null, null, null, null];
    }
    // 0b. Teplá voda + ideál splněn (čerstvě dnes) + povinný blok hotov → není důvod (§10.5 a)
    if (warm && orpIdealMet && orpFreshToday && mandatoryMet) {
        global.set("filtrace_status", {run: run, target: target, half: HALF, met: true, orp: orp, band: band, idealMet: true});
        node.status({fill: "green", shape: "dot", text: "Ideál ORP " + orp + "≥" + ORP_IDEAL + " | " + run + "min"});
        return [null, null, null, null];
    }
    // 0c. NIBE kompresor → pauza JEN když povinný blok hotov (jinak má blok přednost, §10.6)
    if (nibeComp && !isZapNak && mandatoryMet) {
        global.set("filtrace_status", {run: run, target: target, half: HALF, met: run >= D, orp: orp, band: band});
        node.status({fill: "grey", shape: "ring", text: "NIBE komp. → pauza | " + run + "min"});
        return [null, null, null, null];
    }
    // HOTOVO DNES (čas + min chlorace) → filtrace se UŽ NEZAPNE (výjimka: finanční dump níže)
    if (doneToday && !financialRun) {
        global.set("filtrace_status", {run: run, target: target, half: HALF, met: true, orp: orp, band: band, doneToday: true, remaining: 0});
        node.status({fill: "green", shape: "ring", text: "Hotovo dnes " + run + "/" + D + "m + ORP \u2713 | klid"});
        return [null, null, null, null];
    }
    // 1. Finanční dump (záporná cena / omezení výroby) — povolený extra běh
    if (financialRun) { act = "on"; rsn = isZapNak ? ("Záporná cena, volno " + Math.round(maxGrid - gridDraw) + "W") : ("Dump omez. výroby, sell " + sellNow.toFixed(2)); }
    // 2. Povinný blok D/2 (potřeba) + dobré okno → ON
    else if (!mandatoryMet && goodWindow) { act = "on"; rsn = "Povinný blok " + HALF + "min, okno"; }
    // 3. Povinný blok D/2 (potřeba) + urgentní deadline → ON i z gridu (bez ohledu na FVE)
    else if (!mandatoryMet && urgentMand) { act = "on"; rsn = "Deadline povinný blok " + HALF + "min"; }
    // 4. Nedosaženo D + dobré okno → ON (doháníme dobu za výhodných podmínek)
    else if (!met && goodWindow) { act = "on"; rsn = "Doba " + run + "/" + D + "min, okno"; }
    // 5. Teplá + chlorace pod min + FREE okno → ON (dohánění chlorace nad rámec D, jen zdarma)
    else if (warm && orpBelowMin && chaseWindow) { act = "on"; rsn = "Chlorace " + (orp || "?") + "<" + ORP_MIN + ", přebytek"; }

    // Ochrana noční rezervy: nepouštět nad rámec povinného bloku, když baterie u rezervy a není free energie
    if (act === "on" && mandatoryMet && batLowForNight && !gSurp && !isZapNak) {
        act = "none"; rsn = "Noční rezerva SOC " + soc + "% <= " + nightReserveSoc + "%";
    }
    // Anti-cycling (mimo urgentní povinný blok)
    if (act === "on" && (now - lastOff) < ANTI && !urgentMand) { act = "none"; rsn = ""; }

} else {
    // --- BĚŽÍ ---
    // 0a. Hard cut-off → OFF
    if (coldLock) { act = "off"; rsn = "Pool " + poolT + "°C < " + T_MIN + "°C"; }
    // HOTOVO DNES (čas + min chlorace) → OFF (pokud není finanční důvod). Fin. dump → drž běh.
    else if (doneToday && !financialRun) { act = "off"; rsn = "Hotovo dnes " + run + "/" + D + "m (čas+ORP)"; }
    else if (doneToday && financialRun) { act = "none"; rsn = "Fin. dump (" + (isZapNak ? "zap.cena" : "omez.výroby") + ")"; }
    // 1. Teplá + ideál splněn → OFF (jediná výjimka: smí přerušit i nedokončený blok, §10.5 a)
    else if (warm && orpIdealMet) { act = "off"; rsn = "Ideál ORP " + orp + "≥" + ORP_IDEAL; }
    // 2. SOUVISLÝ BLOK: dokud contRun < HALF → NEPŘERUŠOVAT (bez ohledu na FVE, §10.2)
    else if (!blockOk && !coldLock) { act = "none"; rsn = "Blok " + contRunMin.toFixed(0) + "/" + HALF + "min"; }
    // --- blok hotov (contRun >= HALF): vyhodnocení vypnutí ---
    else if (isZapNak && !hasHeadroom) { act = "off"; rsn = "Záporná: jistič " + Math.round(gridDraw) + "/" + maxGrid + "W"; }
    // 3. STUDENÁ: dosaženo D → OFF
    else if (!warm && met && !isZapNak) { act = "off"; rsn = "Studená OK " + run + "/" + D + "min"; }
    // 4. TEPLÁ: dosaženo D a chlorace není pod min → OFF
    else if (warm && met && !orpBelowMin && !isZapNak) { act = "off"; rsn = "OK " + run + "/" + D + "min, ORP " + (orp || "?"); }
    // 5. Ochrana baterie (nad rámec povinného bloku): nízký SOC + žádný přebytek → OFF
    else if (mandatoryMet && !oSurp && !isZapNak && (batLowForNight || (inNormal && lowSOC))) {
        act = "off"; rsn = "Ochrana baterie SOC " + soc + "% (rezerva " + nightReserveSoc + "%)";
    }
    // 6. TEPLÁ chlorace pod min: drž jen za přebytku, jinak pauza (čekej na okno / další den)
    else if (warm && orpBelowMin && !oSurp && !isZapNak) { act = "off"; rsn = "Pauza chlorace (bez přebytku) → další okno"; }
    // 7. Nedosaženo D + přebytek klesl + budoucí solar → PAUZA
    else if (!met && !oSurp && hasFutureSolar && !isZapNak) { act = "off"; rsn = "Pauza → čeká solar (" + solRemain.toFixed(0) + "kWh)"; }
    // 8. Nedosaženo D + přebytek klesl + normal → PAUZA
    else if (!met && !oSurp && !inSetrit && !isZapNak) { act = "off"; rsn = "Pauza (normal, SOC " + soc + "%)"; }

    // Anti-cycling při vypnutí (mimo NIBE/cold/ideál/dosažení)
    if (act === "off" && (now - lastOn) < ANTI && !nibeComp && !coldLock && !met && !orpIdealMet && blockOk) {
        act = "none"; rsn = "";
    }
}
} else {
    rsn = "Ruční režim (měření času)";
}

// Track transitions
if (act === "on") flow.set("filt_on_ts", now);
if (act === "off") flow.set("filt_off_ts", now);

// === Status ===
var bandTag = warm ? "T" : (coldLock ? "❄" : "S");
var st = bandTag + (fOn ? "•ON" : "•OFF") + " " + run + "/" + D + "m";
if (fOn) st += " blk:" + contRunMin.toFixed(0) + "/" + HALF;
st += " ΔP:" + Math.round(surplus) + "W SOC:" + soc + "% " + mode;
st += " T:" + poolT + "°C";
if (warm) st += " ORP:" + (orpValid ? orp : "?") + (orpFreshToday ? "" : "(old)") + "/" + ORP_IDEAL;
if (hasFutureSolar) st += " ☀" + solRemain.toFixed(0);
if (isZapNak) st += " 💰ZAP";
if (act !== "none") st += " → " + act + ": " + rsn;
var cl = act === "on" ? "blue" : act === "off" ? "yellow" : (fOn ? "green" : "grey");
node.status({fill: cl, shape: "dot", text: st});

// === Výstupy [0]=ON, [1]=OFF, [2]=flag_on, [3]=flag_off ===
var out = [null, null, null, null];
if (act === "on") out[0] = {payload: "on", reason: rsn};
if (act === "off") out[1] = {payload: "off", reason: rsn};
if (act === "on" && gSurp) out[2] = {payload: "on"};
if (newDay) out[3] = {payload: "off"};

global.set("filtrace_status", {run: run, target: D, half: HALF, met: met, blockDone: mandatoryMet,
    orp: orp, orpFresh: orpFreshToday, idealMet: orpIdealMet, belowMin: orpBelowMin, band: band,
    remaining: Math.max(0, D - run)});

return out;
